"use client";

import { useState, useEffect, useCallback } from "react";
import { ArcElement, Chart as ChartJS, Legend, Tooltip } from "chart.js";
import { Pie } from "react-chartjs-2";
import { useUser, useSession } from "@clerk/nextjs";
import { createClient } from "@supabase/supabase-js";

ChartJS.register(ArcElement, Tooltip, Legend);

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;

// Definisco le categorie fuori dal componente per non ricrearle
const categorieIniziali = [
  { nome: "Alimenti", totale: 0, icona: "🛒" },
  { nome: "Ristoranti", totale: 0, icona: "🍽️" },
  { nome: "Salute", totale: 0, icona: "💊" },
  { nome: "Lavoro", totale: 0, icona: "💼" },
  { nome: "Cancelleria", totale: 0, icona: "📎" },
  { nome: "Software", totale: 0, icona: "💻" },
  { nome: "Auto/Trasporti", totale: 0, icona: "🚗" },
  { nome: "Carburante", totale: 0, icona: "⛽" },
  { nome: "Viaggi", totale: 0, icona: "✈️" },
  { nome: "Tasse", totale: 0, icona: "🏦" },
  { nome: "Senza Tasse", totale: 0, icona: "🆓" },
  { nome: "Utenze", totale: 0, icona: "💡" },
  { nome: "Formazione", totale: 0, icona: "📚" },
  { nome: "Abbigliamento", totale: 0, icona: "👔" },
  { nome: "Imprevisti", totale: 0, icona: "⚠️" },
  { nome: "Altro", totale: 0, icona: "📦" },
];

export default function Dashboard() {
  const { isLoaded, isSignedIn, user } = useUser();
  const { session } = useSession();
  const [selectedCategory, setSelectedCategory] = useState<{ nome: string, totale: number, icona: string } | null>(null);

  const getSupabase = useCallback(() => {
    return createClient(supabaseUrl, supabaseKey, {
      global: {
        fetch: async (url, options = {}) => {
          let clerkToken;
          try {
            clerkToken = await session?.getToken({ template: 'supabase' });
          } catch {
            console.warn("Nessun template 'supabase' trovato in Clerk, uso token default");
            clerkToken = await session?.getToken(); // Fallback
          }
          const headers = new Headers(options?.headers);
          if (clerkToken) headers.set('Authorization', `Bearer ${clerkToken}`);
          return fetch(url, { ...options, headers, cache: 'no-store' });
        },
      },
    });
  }, [session]);

  // Dati Dinamici
  const [entrateMensili, setEntrateMensili] = useState(0);
  const [usciteMensili, setUsciteMensili] = useState(0);
  const [tasseMensiliAccantonate, setTasseMensiliAccantonate] = useState(0);
  const [categorieSpesa, setCategorieSpesa] = useState(categorieIniziali);
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const [transazioniMese, setTransazioniMese] = useState<any[]>([]);
  const [limiteRistorantiInfo, setLimiteRistorantiInfo] = useState<{ limite: number; speso: number; percentuale: number; superato: boolean } | null>(null);
  const [regimeCorrente, setRegimeCorrente] = useState<string | null>(null);

  const [sogliaFaccina, setSogliaFaccina] = useState(40);
  const [showGuida, setShowGuida] = useState(false);

  // Rimosso useEffect anticipato

  const caricaDatiMensili = useCallback(async () => {
    const today = new Date();
    const startOfMonth = `${today.getFullYear()}-${String(today.getMonth() + 1).padStart(2, '0')}-01`;

    try {
      const supabase = getSupabase();

      // 0. Carica Profilo Utente (Regime, Faccina, Irpef)
      const { data: profile, error: errProfile } = await supabase
        .from('profiles')
        .select('*')
        .eq('user_id', user?.id)
        .single();

      let currentScaglione = 23;
      if (profile && !errProfile) {
        if (profile.sad_face_threshold) setSogliaFaccina(profile.sad_face_threshold);
        if (profile.expected_irpef_bracket) {
          currentScaglione = parseInt(profile.expected_irpef_bracket);
        }
      }

      // 1. Carica le Cause
      const { data: cause, error: errCause } = await supabase
        .from('cause')
        .select('*')
        .eq('user_id', user?.id)
        .gte('data_sentenza', startOfMonth);

      if (errCause) {
        console.error("Errore fetch cause mensili: ", errCause.message);
      }

      let totEntrate = 0;
      let totTasseAccantonate = 0;

      if (cause) {
        cause.forEach(c => {
          const importo = Number(c.compenso_lordo || 0);
          totEntrate += importo;
        });
      }

      // 2. Carica le Uscite (Transazioni)
      const { data: uscite, error: errUscite } = await supabase
        .from('transazioni')
        .select('id, importo, categoria, descrizione, data_transazione, created_at, importo_deducibile')
        .eq('user_id', user?.id)
        .eq('tipo', 'uscita')
        .gte('data_transazione', startOfMonth)
        .order('created_at', { ascending: false });

      if (errUscite) {
        console.error("Errore fetch uscite mensili: ", errUscite.message);
        alert("Errore nel caricamento spese: " + errUscite.message);
      }

      let totUsciteLorde = 0;
      let totUsciteDeducibili = 0;
      const nuoveCategorie = categorieIniziali.map(c => ({ ...c, totale: 0 })); // Reset

      if (uscite) {
        setTransazioniMese(uscite);
        uscite.forEach(u => {
          const importoNumerico = Number(u.importo);
          totUsciteLorde += importoNumerico;
          // Usa importo_deducibile se presente (post-aggiornamento), altrimenti usa il lordo
          totUsciteDeducibili += Number(u.importo_deducibile ?? importoNumerico);

          const catIndex = nuoveCategorie.findIndex(c => c.nome === u.categoria);
          if (catIndex !== -1) {
            nuoveCategorie[catIndex].totale += importoNumerico;
          } else {
            nuoveCategorie[nuoveCategorie.length - 1].totale += importoNumerico; // 'Altro'
          }
        });
      }

      // 3. Calcolo Finanziario Combinato (Entrate e Tasse)
      totTasseAccantonate = 0;
      if (cause) {
        cause.forEach(c => {
          const tipoFiscale = c.tipologia_fiscale || "forfettario_15";

          if (tipoFiscale === "forfettario_5" || tipoFiscale === "forfettario_15") {
            // Modello FORFETTARIO
            const compensoPuro = Number(c.compenso_base || c.compenso_lordo || 0);
            const speseGenerali = compensoPuro * 0.15;
            const redditoImponibileLordo = (compensoPuro + speseGenerali) * 0.78;

            const secchio1_cpa = c.cpa_4 ? Number(c.cpa_4) : (compensoPuro + speseGenerali) * 0.04;
            const secchio2_cassa = redditoImponibileLordo * 0.17;
            const aliquotaFisco = tipoFiscale === "forfettario_5" ? 0.05 : 0.15;
            const secchio3_imposta = redditoImponibileLordo * aliquotaFisco;

            totTasseAccantonate += (secchio1_cpa + secchio2_cassa + secchio3_imposta);

          } else if (tipoFiscale === "ordinario") {
            // Modello ORDINARIO
            const compensoPuro = Number(c.compenso_base || c.compenso_lordo || 0);
            const speseGenerali = compensoPuro * 0.15;

            // EPICA 3: Sottraggo le uscite deducibili dall'Imponibile Cassa per calcolare l' Utile Lordo reale
            const utileLordo = Math.max(0, (compensoPuro + speseGenerali) - totUsciteDeducibili);

            const secchio1_cpa = c.cpa_4 ? Number(c.cpa_4) : (compensoPuro + speseGenerali) * 0.04;
            const secchio2_iva = c.iva_22 ? Number(c.iva_22) : 0;
            const secchio3_cassa = utileLordo * 0.17;

            const percentualeIrpef = currentScaglione / 100.0;
            const baseIrpef = Math.max(0, utileLordo - secchio3_cassa);
            const secchio4_irpef = baseIrpef * percentualeIrpef;
            const secchio5_addizionali = baseIrpef * 0.03; // ~3%

            const scontoRitenuta = c.ritenuta_20 ? Number(c.ritenuta_20) : 0;

            totTasseAccantonate += (secchio1_cpa + secchio2_iva + secchio3_cassa + secchio4_irpef + secchio5_addizionali - scontoRitenuta);

            totUsciteDeducibili = 0; // Evita di ri-sottrarre le stesse spese per le successive fatture dello stesso mese

          } else if (tipoFiscale === "free") {
            totTasseAccantonate += 0;
          }
        });
      }

      // Applica un safety cap
      if (totTasseAccantonate < 0) totTasseAccantonate = 0;

      // EPICA 4: Calcolo YTD (Year-To-Date) per Limite 2% Ristoranti/Trasferte solo per Ordinario
      let isRegimeOrdinario = false;
      if (profile && profile.regime_fiscale === "ordinario") isRegimeOrdinario = true;
      else if (localStorage.getItem("regime_fiscale_generale") === "ordinario") isRegimeOrdinario = true;

      setRegimeCorrente(isRegimeOrdinario ? "ordinario" : "forfettario");

      if (isRegimeOrdinario) {
        const startOfYear = `${today.getFullYear()}-01-01`;
        const { data: allCause } = await supabase.from('cause').select('compenso_base, compenso_lordo').eq('user_id', user?.id).gte('data_sentenza', startOfYear);
        let ytdCompensi = 0;
        if (allCause) {
          allCause.forEach(c => ytdCompensi += Number(c.compenso_base || c.compenso_lordo || 0));
        }

        const { data: allUscite } = await supabase.from('transazioni').select('importo, categoria').eq('user_id', user?.id).eq('tipo', 'uscita').gte('data_transazione', startOfYear);
        let ytdRistoranti = 0;
        if (allUscite) {
          allUscite.forEach(u => {
            if (u.categoria === "Ristoranti" || u.categoria === "Ristoranti / Trasferte" || u.categoria?.toLowerCase().includes("ristorant")) {
              ytdRistoranti += Number(u.importo);
            }
          });
        }

        // La legge dice il 2% del totale compensi percepiti
        const limite = ytdCompensi * 0.02;
        const pct = limite > 0 ? (ytdRistoranti / limite) * 100 : 0;
        setLimiteRistorantiInfo({
          limite: limite,
          speso: ytdRistoranti,
          percentuale: pct,
          superato: ytdRistoranti >= limite
        });
      }

      setEntrateMensili(totEntrate);
      setTasseMensiliAccantonate(totTasseAccantonate);
      setUsciteMensili(totUsciteLorde);
      setCategorieSpesa(nuoveCategorie);

    } catch (error) {
      console.error("Errore recupero dashboard:", error);
    }
  }, [getSupabase, user]);

  useEffect(() => {
    // Si cerca prima nel local storage come fallback rapido
    const savedSoglia = localStorage.getItem("soglia_faccina");
    if (savedSoglia) setSogliaFaccina(Number(savedSoglia));

    if (isSignedIn && user) {
      caricaDatiMensili();
    }
  }, [isSignedIn, user, caricaDatiMensili]);

  const handleDeleteTransazione = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const confirmed = window.confirm("Sei sicuro di voler eliminare questa spesa?");
    if (!confirmed) return;

    try {
      const supabase = getSupabase();
      const { error } = await supabase
        .from('transazioni')
        .delete()
        .eq('id', id)
        .eq('user_id', user?.id);

      if (error) throw error;

      await caricaDatiMensili();
      setSelectedCategory(null); // Chiude o rinfresca il modale
    } catch (err: unknown) {
      console.error(err);
      const msg = err instanceof Error ? err.message : String(err);
      alert("Errore nell&apos;eliminazione: " + msg);
    }
  };

  const nettoMensile = entrateMensili - usciteMensili - tasseMensiliAccantonate;
  // Per il grafico a torta, non possiamo avere valori negativi. 
  // Se le uscite superano le entrate, il "netto puro" mostrato nella torta deve essere semplicemente 0 (o un minimo per non rompere il rendering)
  const nettoPuroGrafico = Math.max(0.1, nettoMensile);

  // Percentuale allarme su Uscite rispetto alle Entrate (ma escludendo le tasse fisse dal calcolo di "sto spendendo troppo")
  const entrateVerificabili = entrateMensili > 0 ? entrateMensili : 1;
  const uscitePercentuale = (usciteMensili / entrateVerificabili) * 100;
  const emoticonInfo = uscitePercentuale > sogliaFaccina ? "😢" : "😀";

  const dataMensile = {
    labels: ['Netto Pulito', 'Spese', 'Tasse Accantonate'],
    datasets: [
      {
        data: [nettoPuroGrafico, usciteMensili > 0 ? usciteMensili : 0.1, tasseMensiliAccantonate > 0 ? tasseMensiliAccantonate : 0.1],
        backgroundColor: (nettoPuroGrafico === 0.1 && usciteMensili === 0 && tasseMensiliAccantonate === 0)
          ? ['#e5e5ea', '#e5e5ea', '#e5e5ea']
          : ['#34c759', '#ff3b30', '#ff9f0a'],
        borderWidth: 0,
      },
    ],
  };

  // La torta annuale per ora la lasciamo vuota/placeholder fino al prossimo upgrade
  const dataAnnuale = {
    labels: ['Entrate Nette', 'Uscite'],
    datasets: [
      {
        data: [0.1, 0.1],
        backgroundColor: ['rgba(229, 229, 234, 0.8)', 'rgba(229, 229, 234, 0.8)'],
        borderWidth: 0,
      },
    ],
  };

  if (!isLoaded || !isSignedIn) {
    return null; // O caricamento
  }

  // Filtra transazioni per la modale se aperta
  const transazioniDellaCategoria = selectedCategory
    ? transazioniMese.filter(t => t.categoria === selectedCategory.nome)
    : [];

  return (
    <div className="pb-20">
      <div className="flex-row-between" style={{ marginBottom: "1.5rem" }}>
        <div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <h2 style={{ margin: 0 }}>Ciao, {user?.firstName || 'Avvocato'}! {emoticonInfo}</h2>
            <button
              onClick={() => setShowGuida(true)}
              style={{ background: 'none', border: 'none', fontSize: '1.5rem', cursor: 'pointer', padding: 0 }}
              title="Guida Fiscale e Tutorial"
            >
              📘
            </button>
          </div>
          <p style={{ color: "var(--foreground)", opacity: 0.6, fontSize: "0.9rem", marginTop: "-4px" }}>Mese Corrente</p>
        </div>

        {/* Torta Annuale (Piccola in alto a dx - La manteniamo fissa come design target per ora) */}
        <div style={{ width: "80px", height: "80px" }}>
          <Pie data={dataAnnuale} options={{ plugins: { legend: { display: false } } }} />
        </div>
      </div>

      {/* Torta Mensile (Grande Centrale) */}
      <div className="ios-card" style={{ display: "flex", flexDirection: "column", alignItems: "center" }}>
        <h3>Bilancio Mensile</h3>

        <div className="chart-container-large" style={{ margin: "1rem 0" }}>
          <Pie
            data={dataMensile}
            options={{
              responsive: true,
              maintainAspectRatio: true,
              plugins: {
                legend: { position: "bottom", labels: { font: { size: 14 } } }
              }
            }}
          />
        </div>

        <div className="flex-row-between" style={{ width: "100%", marginTop: "1rem", flexWrap: "wrap", justifyContent: "space-around" }}>
          <div style={{ textAlign: "center", marginBottom: "0.5rem" }}>
            <span style={{ fontSize: "0.8rem", opacity: 0.7 }}>In Tasca</span>
            <div style={{ fontSize: "1.2rem", fontWeight: "bold", color: "var(--success)" }}>€{nettoMensile.toFixed(2)}</div>
          </div>
          <div style={{ textAlign: "center", marginBottom: "0.5rem" }}>
            <span style={{ fontSize: "0.8rem", opacity: 0.7 }}>Lordo Inc.</span>
            <div style={{ fontSize: "1.2rem", fontWeight: "bold", color: "var(--foreground)" }}>€{entrateMensili.toFixed(2)}</div>
          </div>
          <div style={{ textAlign: "center", marginBottom: "0.5rem" }}>
            <span style={{ fontSize: "0.8rem", opacity: 0.7 }}>Spese Voc.</span>
            <div style={{ fontSize: "1.2rem", fontWeight: "bold", color: "var(--destructive)" }}>€{usciteMensili.toFixed(2)}</div>
          </div>
        </div>
        <div style={{ width: "100%", textAlign: "center", marginTop: "0.5rem", borderTop: "1px solid var(--border)", paddingTop: "0.5rem" }}>
          <span style={{ fontSize: "0.8rem", opacity: 0.7, marginRight: "10px" }}>Fondo Tasse Virt.:</span>
          <span style={{ fontSize: "1rem", fontWeight: "bold", color: "#ff9f0a" }}>€{tasseMensiliAccantonate.toFixed(2)}</span>
        </div>
      </div>

      {/* ALERT GAMIFICATION FISCALE (EPICA 4) */}
      {regimeCorrente === "ordinario" && limiteRistorantiInfo && limiteRistorantiInfo.limite > 0 && limiteRistorantiInfo.percentuale >= 75 && (
        <div className="ios-card" style={{ marginTop: "1rem", backgroundColor: limiteRistorantiInfo.superato ? "rgba(255, 59, 48, 0.1)" : "rgba(255, 149, 0, 0.1)", border: `1px solid ${limiteRistorantiInfo.superato ? "var(--destructive)" : "#ff9f0a"}`, animation: "fadeIn 0.5s" }}>
          <div style={{ display: "flex", gap: "12px", alignItems: "flex-start" }}>
            <div style={{ fontSize: "2rem" }}>{limiteRistorantiInfo.superato ? "🛑" : "⚠️"}</div>
            <div>
              <h4 style={{ margin: "0 0 4px 0", color: limiteRistorantiInfo.superato ? "var(--destructive)" : "#cc7e00" }}>
                {limiteRistorantiInfo.superato ? "Limite Ristoranti Superato" : "Attenzione: Limite Ristoranti Vicino"}
              </h4>
              <p style={{ fontSize: "0.85rem", margin: 0, opacity: 0.9 }}>
                {limiteRistorantiInfo.superato
                  ? `Hai superato il limite di legge del 2% annuo per dedurre i pasti (Speso: €${limiteRistorantiInfo.speso.toFixed(2)} / Limite: €${limiteRistorantiInfo.limite.toFixed(2)}). Le prossime fatture al ristorante non abbatteranno più le tue tasse.`
                  : `Sei al ${limiteRistorantiInfo.percentuale.toFixed(0)}% del limite annuo (2% dei compensi) per ristoranti e hotel. (Speso: €${limiteRistorantiInfo.speso.toFixed(2)} / Limite: €${limiteRistorantiInfo.limite.toFixed(2)}).`
                }
              </p>
            </div>
          </div>
        </div>
      )}

      <h2 style={{ marginTop: "2rem" }}>Spese Settoriali Mensili</h2>
      <p style={{ fontSize: "0.9rem", opacity: 0.7 }}>Dal 1° del Mese</p>

      {/* Grid Card Stile Apple Wallet */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "10px" }}>
        {categorieSpesa.map((cat, idx) => (
          <div
            key={idx}
            className="ios-card"
            style={{ padding: "1rem", marginBottom: "0", cursor: "pointer" }}
            onClick={() => setSelectedCategory(cat)}
          >
            <div style={{ fontSize: "2rem", marginBottom: "0.5rem" }}>{cat.icona}</div>
            <div style={{ fontSize: "1rem", fontWeight: "600" }}>{cat.nome}</div>
            <div style={{ fontSize: "1.1rem", opacity: 0.8 }}>€{cat.totale.toFixed(2)}</div>
          </div>
        ))}
      </div>

      {/* Bottom Sheet Modale */}
      {selectedCategory && (
        <div className="bottom-sheet-overlay" onClick={() => setSelectedCategory(null)}>
          <div className="bottom-sheet" onClick={(e) => e.stopPropagation()}>
            <div className="bottom-sheet-handle"></div>
            <button className="bottom-sheet-close" onClick={() => setSelectedCategory(null)}>&times;</button>

            <div style={{ textAlign: "center", marginTop: "1rem", marginBottom: "1rem" }}>
              <div style={{ fontSize: "4rem", marginBottom: "1rem" }}>{selectedCategory.icona}</div>
              <h2>{selectedCategory.nome}</h2>
              <p style={{ fontSize: "1.5rem", fontWeight: "bold", color: "var(--primary)" }}>
                Totale Mese: €{selectedCategory.totale.toFixed(2)}
              </p>
            </div>

            <div style={{ padding: "0 1rem", maxHeight: "40vh", overflowY: "auto" }}>
              {transazioniDellaCategoria.length === 0 ? (
                <div style={{ textAlign: "center", opacity: 0.5, padding: "2rem" }}>
                  Nessuna transazione per questa categoria.
                </div>
              ) : (
                transazioniDellaCategoria.map((t) => (
                  <div key={t.id} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "10px 0", borderBottom: "1px solid var(--border)" }}>
                    <div style={{ textAlign: "left" }}>
                      <div style={{ fontWeight: "600" }}>{t.descrizione || t.categoria}</div>
                      <div style={{ fontSize: "0.8rem", opacity: 0.6 }}>{t.data_transazione}</div>
                    </div>
                    <div style={{ display: "flex", alignItems: "center", gap: "10px" }}>
                      <span style={{ fontWeight: "bold", color: "var(--destructive)" }}>€{Number(t.importo).toFixed(2)}</span>
                      <button
                        onClick={(e) => handleDeleteTransazione(t.id, e)}
                        style={{ background: "none", border: "none", color: "var(--destructive)", fontSize: "1.2rem", cursor: "pointer" }}
                      >
                        🗑️
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>

            <div style={{ textAlign: "center" }}>
              <button
                className="ios-btn-large"
                style={{ marginTop: "2rem" }}
                onClick={() => setSelectedCategory(null)}
              >
                Chiudi
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modale Guida e Tutorial App */}
      {showGuida && (
        <div className="bottom-sheet-overlay" onClick={() => setShowGuida(false)} style={{ zIndex: 1000 }}>
          <div className="bottom-sheet" onClick={(e) => e.stopPropagation()} style={{ height: '85vh', maxHeight: '85vh', display: 'flex', flexDirection: 'column' }}>
            <div className="bottom-sheet-handle"></div>
            <button className="bottom-sheet-close" onClick={() => setShowGuida(false)}>&times;</button>

            <div style={{ padding: "0 1rem 2rem 1rem", overflowY: "auto", flex: 1 }}>
              <h2 style={{ marginBottom: "1.5rem", textAlign: "center", fontSize: "1.5rem" }}>📘 Guida & Tutorial</h2>

              <div className="ios-card" style={{ marginBottom: "1rem" }}>
                <h3 style={{ color: "var(--primary)", marginBottom: "0.5rem" }}>Il Nuovo Motore Fiscale</h3>
                <p style={{ fontSize: "0.9rem", lineHeight: "1.5", opacity: 0.9, marginBottom: "0.5rem" }}>
                  <strong>1. Badge in Tempo Reale:</strong> Inserendo una spesa manualmente o scansionando uno scontrino, vedrai comparire un avviso in tempo reale con l&apos;esatto importo deducibile (es: amount * deductibilityRate) calcolato matematicamente al volo.
                </p>
                <p style={{ fontSize: "0.9rem", lineHeight: "1.5", opacity: 0.9, marginBottom: "0.5rem" }}>
                  <strong>2. Tasse Abbattute in Diretta (Ordinario):</strong> La Dashboard "sottrae" automaticamente il totale delle spese legalmente deducibili dal tuo imponibile. Noterai il tuo <em>Fondo Tasse Virt.</em> abbassarsi in tempo reale all&apos;inserimento di ogni scontrino valido!
                </p>
                <p style={{ fontSize: "0.9rem", lineHeight: "1.5", opacity: 0.9, marginBottom: "0.5rem" }}>
                  <strong>3. Tieni d&apos;occhio la Faccina:</strong> L&apos;emoticon in alto valuta la tua spesa globale per frenare il consumismo. Modificabile nelle impostazioni.
                </p>
                <p style={{ fontSize: "0.9rem", lineHeight: "1.5", opacity: 0.9 }}>
                  <strong>4. Gamification Ristoranti:</strong> La legge italiana limita le spese per Ristoranti e Hotel al 2% dei compensi annui (YTD). Se ti avvicini o sfori questo tetto, la UI rivelerà un banner di allerta arancione/rosso sotto il grafico mensile per dirti di non dedurre più!
                </p>
              </div>

              <div className="ios-card" style={{ marginBottom: "2rem" }}>
                <h3 style={{ color: "var(--primary)", marginBottom: "0.5rem" }}>Tassi di Deducibilità Centralizzati</h3>
                <p style={{ fontSize: "0.85rem", opacity: 0.8, marginBottom: "1rem", background: "rgba(255,59,48,0.1)", padding: "10px", borderRadius: "8px", color: "var(--destructive)" }}>
                  <strong>Nota per i Forfettari:</strong> I bonus deducibilità spiegati sopra valgono SOLO per il <strong>Regime Ordinario</strong> (impostabile dal tuo Profilo). I forfettari hanno costi scaricati forfettizzati automaticamente al 15% per legge, indipendenti dalle spese caricate in app.
                </p>
                <ul style={{ fontSize: "0.85rem", paddingLeft: "1.2rem", lineHeight: "1.6", opacity: 0.9 }}>
                  <li style={{ marginBottom: "6px" }}><strong>100%:</strong> Cancelleria, software, formazione, spese di lavoro/ufficio esclusivo.</li>
                  <li style={{ marginBottom: "6px" }}><strong>80%:</strong> Telefonia, internet, utenze promiscue.</li>
                  <li style={{ marginBottom: "6px" }}><strong>75%:</strong> Ristoranti e Trasferte. Il motore incrocia questo rate con il tetto di "plafond" massimo annuo (il tuo 2% dei compensi totali incassati). Oltre questa soglia, non saranno più validi!</li>
                  <li style={{ marginBottom: "6px" }}><strong>50%:</strong> Affitto e Utenze per casa-studio (Promiscuo).</li>
                  <li><strong>20%:</strong> Auto, viaggi vari, mezzi di trasporto, carburante.</li>
                </ul>
                <p style={{ fontSize: "0.75rem", color: "var(--destructive)", marginTop: "1rem", opacity: 0.8 }}>
                  <em>Disclaimer: Le percentuali sono stimate algoritmicamente dal gestionale a titolo informativo basandosi sull&apos;attuale normativa TUIR (Ordinario Avvocati). Il commercialista valuterà caso per caso il reale principio di inerenza e competenza.</em>
                </p>
              </div>

              <button
                className="ios-btn-large"
                onClick={() => setShowGuida(false)}
                style={{ width: "100%", marginTop: "1rem" }}
              >
                Ho Capito
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Footer Legale Interno (Beta) */}
      <div style={{ marginTop: "4rem", paddingTop: "2rem", borderTop: "1px solid var(--border)", textAlign: "center" }}>
        <p style={{ fontSize: "0.75rem", opacity: 0.6, maxWidth: "800px", margin: "0 auto", lineHeight: "1.6" }}>
          <strong>Versione Beta Privata.</strong> Questo gestionale è fornito allo stato attuale come test non a fini commerciali (Senza Partita IVA).
          I calcoli fiscali visualizzati in questa Dashboard (Cassa Forense, IRPEF, Imposta Sostitutiva) hanno puramente valore di simulazione matematica e non costituiscono parere professionale né dato certo per le dichiarazioni fiscali obbligatorie.
          <br /><br />
          <strong>Privacy:</strong> Nessun dato biometrico o immagine di spesa viene trasmesso esternamente (elaborazione OCR su dispositivo). Vengono impiegati esclusivamente cookie tecnici per la validazione della sessione.
        </p>
      </div>

    </div>
  );
}

"use client";

import { useState, useRef, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useUser, useSession } from "@clerk/nextjs";
import { createClient } from "@supabase/supabase-js";

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;

export default function ScannerScontrini() {
    const { isLoaded, isSignedIn, user } = useUser();
    const { session } = useSession();
    const router = useRouter();
    const fileInputRef = useRef<HTMLInputElement>(null);

    const parseImporto = (val: string | number) => {
        if (!val) return 0;
        if (typeof val === 'number') return val;
        // Se l'utente scrive 1.500,50 rimuove i punti e la virgola diventa punto
        const cleaned = val.replace(/\./g, '').replace(',', '.');
        const parsed = parseFloat(cleaned);
        return isNaN(parsed) ? 0 : parsed;
    };

    const getSupabase = () => {
        return createClient(supabaseUrl, supabaseKey, {
            global: {
                fetch: async (url, options = {}) => {
                    let clerkToken;
                    try {
                        clerkToken = await session?.getToken({ template: 'supabase' });
                    } catch {
                        console.warn("Nessun template 'supabase' trovato in Clerk, uso token default");
                        clerkToken = await session?.getToken();
                    }
                    const headers = new Headers(options?.headers);
                    if (clerkToken) headers.set('Authorization', `Bearer ${clerkToken}`);
                    return fetch(url, { ...options, headers, cache: 'no-store' });
                },
            },
        });
    };

    const [file, setFile] = useState<File | null>(null);
    const [preview, setPreview] = useState<string | null>(null);
    const [isScanning, setIsScanning] = useState(false);
    const [scannedData, setScannedData] = useState<{
        importo: number;
        categoria: string;
        testoEstratto: string;
    } | null>(null);

    // Stato form manuale
    const [spesaManuale, setSpesaManuale] = useState({ importo: "", categoria: "Altro", descrizione: "" });
    const [isSaving, setIsSaving] = useState(false);

    const handleCapture = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            const selectedFile = e.target.files[0];
            setFile(selectedFile);

            const reader = new FileReader();
            reader.onloadend = () => {
                setPreview(reader.result as string);
            };
            reader.readAsDataURL(selectedFile);
            setScannedData(null);
        }
    };

    const scansionaImmagine = async () => {
        if (!file) return;
        setIsScanning(true);

        const base64Data = await new Promise<string>((resolve) => {
            const reader = new FileReader();
            reader.onload = (event) => {
                const img = new window.Image();
                img.onload = () => {
                    let MAX_DIM = 1000;
                    let quality = 0.7;
                    let dataUrl = "";
                    let pass = 0;

                    do {
                        let width = img.width;
                        let height = img.height;

                        if (width > height) {
                            if (width > MAX_DIM) {
                                height = Math.round((height * MAX_DIM) / width);
                                width = MAX_DIM;
                            }
                        } else {
                            if (height > MAX_DIM) {
                                width = Math.round((width * MAX_DIM) / height);
                                height = MAX_DIM;
                            }
                        }

                        const canvas = document.createElement('canvas');
                        canvas.width = width;
                        canvas.height = height;
                        const ctx = canvas.getContext('2d');

                        if (ctx) {
                            ctx.fillStyle = '#FFFFFF';
                            ctx.fillRect(0, 0, width, height);
                            ctx.drawImage(img, 0, 0, width, height);
                        }

                        dataUrl = canvas.toDataURL('image/jpeg', quality);
                        MAX_DIM -= 200;
                        quality -= 0.15;
                        pass++;

                    } while (dataUrl.length > 1300000 && pass < 5);

                    resolve(dataUrl);
                };
                img.src = event.target?.result as string;
            };
            reader.readAsDataURL(file);
        });

        try {
            // Utilizzo di Tesseract OCR locale via client-browser (no api payload a pagamento)
            const Tesseract = await import('tesseract.js');
            const result = await Tesseract.recognize(base64Data, 'ita', {
                logger: m => console.log(m)
            });

            const text = result.data.text;
            const testoLows = text.toLowerCase();

            // Estrazione Importo
            let importoEstratto = 0;
            const regexTotale = /(?:totale|importo|pagato|eur|euro|€)\s*[:.-]?\s*(\d{1,4}[.,]\d{2})/ig;
            let match;
            const massimi = [];

            while ((match = regexTotale.exec(testoLows)) !== null) {
                const pulito = match[1].replace(',', '.');
                const num = parseFloat(pulito);
                if (!isNaN(num)) massimi.push(num);
            }

            if (massimi.length > 0) {
                importoEstratto = Math.max(...massimi);
            } else {
                const regexNumeriValuta = /(\d{1,4}[.,]\d{2})/g;
                const matchesArr = Array.from(testoLows.matchAll(regexNumeriValuta)) as RegExpMatchArray[];
                if (matchesArr.length > 0) {
                    const ultimoElemento = matchesArr[matchesArr.length - 1];
                    if (ultimoElemento && ultimoElemento[1]) {
                        const lastMatch = ultimoElemento[1].replace(',', '.');
                        importoEstratto = parseFloat(lastMatch);
                    }
                }
            }

            // Categorizzazione
            let categoriaSuggerita = "Altro";
            if (testoLows.match(/ristorant|pizzer|trattoria|bar |osteria|caff/)) categoriaSuggerita = "Ristoranti";
            else if (testoLows.match(/farmacia|medic|visita|sanit|dott.ssa|dott./)) categoriaSuggerita = "Salute";
            else if (testoLows.match(/carburant|benzi|eni|q8|agip|tamoil|ip |diesel|verde|gasolio/)) categoriaSuggerita = "Carburante";
            else if (testoLows.match(/conad|coop|esselunga|pam|lidl|eurospin|despar|supermercat/)) categoriaSuggerita = "Alimenti";
            else if (testoLows.match(/treno|italo|trenitalia|taxi|bus|metropolitana/)) categoriaSuggerita = "Auto/Trasporti";
            else if (testoLows.match(/cartoleria|buffetti|carta|penna/)) categoriaSuggerita = "Cancelleria";
            else if (testoLows.match(/amazon|software|abbonament/)) categoriaSuggerita = "Software";

            setScannedData({
                importo: importoEstratto,
                categoria: categoriaSuggerita,
                testoEstratto: text.substring(0, 300) + (text.length > 300 ? "..." : "")
            });

        } catch (err) {
            console.error(err);
            alert("Errore nella scansione locale con Tesseract: " + (err as Error).message);
        } finally {
            setIsScanning(false);
        }
    };

    const salvaSpesaManuale = async () => {
        if (!spesaManuale.importo) {
            alert("Inserisci l'importo della spesa."); return;
        }

        setIsSaving(true);
        try {
            const supabase = getSupabase();
            const now = new Date();
            const data_transazione = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;

            const importoCorretto = parseImporto(spesaManuale.importo);
            const regimeGenerale = localStorage.getItem("regime_fiscale_generale");
            let percentualeDeducibilita = 0;
            if (regimeGenerale === "ordinario") {
                const { getDeductibilityPercentage } = await import('@/lib/deductibility');
                percentualeDeducibilita = getDeductibilityPercentage(spesaManuale.categoria);
            }
            const importoDeducibile = importoCorretto * percentualeDeducibilita;

            const { error } = await supabase.from('transazioni').insert({
                user_id: user?.id,
                tipo: 'uscita',
                importo: importoCorretto,
                categoria: spesaManuale.categoria,
                descrizione: spesaManuale.descrizione,
                data_transazione: data_transazione,
                percentuale_deducibilita: percentualeDeducibilita,
                importo_deducibile: importoDeducibile
            });

            if (error) throw error;

            const deducMsg = regimeGenerale === "ordinario" ? ` (Deducibile al ${percentualeDeducibilita * 100}%)` : ` (Nessuna deduzione in Forfettario)`;
            alert(`Spesa registrata!${deducMsg}`);
            setSpesaManuale({ importo: "", categoria: "Altro", descrizione: "" });
            router.refresh();
            router.push('/dashboard');
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
        } catch (err: any) {
            console.error(err);
            alert("Si è verificato un errore nel salvataggio. Controlla i permessi o le policy: " + err.message);
        } finally {
            setIsSaving(false);
        }
    };

    const salvaScanner = async () => {
        if (!scannedData) return;
        setIsSaving(true);
        try {
            const supabase = getSupabase();
            const now = new Date();
            const data_transazione = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;

            const importoCorretto = parseImporto(scannedData.importo);
            const regimeGenerale = localStorage.getItem("regime_fiscale_generale");
            let percentualeDeducibilita = 0;
            if (regimeGenerale === "ordinario") {
                const { getDeductibilityPercentage } = await import('@/lib/deductibility');
                percentualeDeducibilita = getDeductibilityPercentage(scannedData.categoria);
            }
            const importoDeducibile = importoCorretto * percentualeDeducibilita;

            const { error } = await supabase.from('transazioni').insert({
                user_id: user?.id,
                tipo: 'uscita',
                importo: importoCorretto,
                categoria: scannedData.categoria,
                descrizione: "Auto-Scansione AI (Locale)",
                data_transazione: data_transazione,
                percentuale_deducibilita: percentualeDeducibilita,
                importo_deducibile: importoDeducibile
            });

            if (error) throw error;

            const deducMsg = regimeGenerale === "ordinario" ? ` (Deducibile al ${percentualeDeducibilita * 100}%)` : ` (Nessuna deduzione in Forfettario)`;
            alert(`Scontrino AI registrato!${deducMsg}`);
            setFile(null);
            setPreview(null);
            setScannedData(null);
            router.refresh();
            router.push('/dashboard');
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
        } catch (err: any) {
            console.error(err);
            alert("Si è verificato un errore nel salvataggio scanner. " + err.message);
        } finally {
            setIsSaving(false);
        }
    };

    const [mode, setMode] = useState<"scanner" | "manuale">("scanner");
    const [regimeCorrente, setRegimeCorrente] = useState<string | null>(null);

    // Carica regime utente all'avvio
    useEffect(() => {
        const regime = localStorage.getItem("regime_fiscale_generale");
        setRegimeCorrente(regime);
    }, []);

    // Helper per determinare la percentuale al volo (per la UI sync)
    // Non avvisa import() asincrono in render
    const getPercentualeSync = (cat: string) => {
        import('@/lib/deductibility').then(m => {
            // Facciamo finta di farlo sync o usiamo un dizionario base se non vogliamo refetch
        });
        const catLow = cat.toLowerCase();
        if (catLow.includes("cancelleria") || catLow.includes("software") || catLow.includes("formazione") || catLow.includes("lavoro")) return 1.0;
        if (catLow.includes("ristorant")) return 0.75;
        if (catLow.includes("auto") || catLow.includes("trasporti") || catLow.includes("carburante") || catLow.includes("viaggi")) return 0.20;
        if (catLow.includes("uso promiscuo") || catLow.includes("telefonia") || catLow.includes("utenze")) return 0.80; // approssimazione
        return 0.0;
    };

    // Variabili calcolate al volo per Manuale
    const importoCorrettoManuale = parseImporto(spesaManuale.importo);
    const percentualeAttualeManuale = getPercentualeSync(spesaManuale.categoria);

    // Variabili calcolate al volo per Scanner
    const importoCorrettoScanner = scannedData ? parseImporto(scannedData.importo) : 0;
    const percentualeAttualeScanner = scannedData ? getPercentualeSync(scannedData.categoria) : 0;

    if (!isLoaded || !isSignedIn) return null;

    return (
        <div className="pb-20">
            <h1>Aggiungi Spesa</h1>

            <div className="ios-select-group" style={{ marginBottom: "2rem" }}>
                <button
                    className={`ios-segment ${mode === 'scanner' ? 'active' : ''}`}
                    onClick={() => setMode('scanner')}
                >
                    📸 Scanner AI
                </button>
                <button
                    className={`ios-segment ${mode === 'manuale' ? 'active' : ''}`}
                    onClick={() => setMode('manuale')}
                >
                    ✍️ Manuale
                </button>
            </div>

            {mode === 'scanner' ? (
                <>
                    <p>Scatta una foto a scontrini o fatture di spesa. L&apos;AI estrarrà l&apos;importo e proporrà una categoria.</p>
                    <div className="ios-card" style={{ textAlign: "center" }}>
                        {preview ? (
                            <div style={{ marginBottom: "1.5rem" }}>
                                <img
                                    src={preview}
                                    alt="Anteprima Scontrino"
                                    style={{ maxWidth: "100%", maxHeight: "300px", borderRadius: "12px" }}
                                />
                            </div>
                        ) : (
                            <div
                                style={{
                                    height: "200px",
                                    background: "var(--background)",
                                    borderRadius: "12px",
                                    display: "flex",
                                    justifyContent: "center",
                                    alignItems: "center",
                                    marginBottom: "1.5rem",
                                    border: "2px dashed var(--border)"
                                }}
                            >
                                <span style={{ fontSize: "3rem", opacity: 0.5 }}>📸</span>
                            </div>
                        )}

                        <input
                            type="file"
                            accept="image/*"
                            capture="environment" // Forza la fotocamera posteriore su iOS
                            ref={fileInputRef}
                            onChange={handleCapture}
                            style={{ display: "none" }}
                        />

                        <div style={{ display: "flex", gap: "10px" }}>
                            <button
                                className="ios-btn-small"
                                style={{ flex: 1, padding: "12px", background: "var(--foreground)", color: "var(--background)" }}
                                onClick={() => fileInputRef.current?.click()}
                            >
                                {preview ? "Scatta di Nuovo" : "Apri Fotocamera"}
                            </button>

                            {preview && (
                                <button
                                    className="ios-btn-small"
                                    style={{ flex: 1, padding: "12px" }}
                                    onClick={scansionaImmagine}
                                    disabled={isScanning}
                                >
                                    {isScanning ? "Scansione..." : "Scansiona AI"}
                                </button>
                            )}
                        </div>
                    </div>

                    {scannedData && (
                        <div className="ios-card" style={{ marginTop: "1rem", animation: "slideUp 0.3s" }}>
                            <h3 style={{ marginBottom: "1rem" }}>Risultato Scansione</h3>

                            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "0.5rem" }}>
                                <span style={{ opacity: 0.7 }}>Importo Estratto</span>
                                <span style={{ fontSize: "1.2rem", fontWeight: "bold", color: "var(--destructive)" }}>
                                    €{scannedData.importo.toFixed(2)}
                                </span>
                            </div>

                            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "1rem" }}>
                                <span style={{ opacity: 0.7 }}>Categoria Suggerita</span>
                                <span style={{ fontSize: "1.1rem", fontWeight: "600", color: "var(--primary)" }}>
                                    {scannedData.categoria}
                                </span>
                            </div>

                            <div style={{ background: "var(--background)", padding: "10px", borderRadius: "8px", fontSize: "0.85rem", opacity: 0.8, maxHeight: "100px", overflowY: "auto", marginBottom: "1.5rem" }}>
                                {scannedData.testoEstratto}
                            </div>

                            {/* BADGE DEDUCIBILITA' IN TEMPO REALE SCANSIONE */}
                            {regimeCorrente === "ordinario" && importoCorrettoScanner > 0 && (
                                <div style={{ marginBottom: "1.5rem", padding: "10px", background: "rgba(52, 199, 89, 0.1)", border: "1px solid var(--success)", borderRadius: "8px", color: "var(--success)", fontSize: "0.9rem", display: "flex", alignItems: "center", gap: "8px", animation: "slideUp 0.3s ease-out" }}>
                                    <span style={{ fontSize: "1.2rem" }}>💡</span>
                                    <div>
                                        <strong>Ordinario:</strong> Importo deducibile stimato
                                        <div style={{ fontWeight: "bold", fontSize: "1.1rem", marginTop: "4px" }}>€{(importoCorrettoScanner * percentualeAttualeScanner).toFixed(2)} ({percentualeAttualeScanner * 100}%)</div>
                                    </div>
                                </div>
                            )}

                            <button className="ios-btn-large" style={{ background: "var(--success)" }} onClick={salvaScanner} disabled={isSaving}>
                                {isSaving ? "Salvataggio..." : `Conferma e Salva in ${scannedData.categoria}`}
                            </button>
                        </div>
                    )}
                </>
            ) : (
                <div className="ios-card" style={{ animation: "fadeIn 0.3s" }}>
                    <h3 style={{ marginBottom: "1rem" }}>Inserimento Manuale</h3>

                    <label style={{ display: "block", marginBottom: "0.5rem", fontSize: "0.9rem", opacity: 0.7 }}>Importo (€)</label>
                    <input
                        type="text"
                        inputMode="decimal"
                        placeholder="Es. 45.50"
                        className="ios-input"
                        value={spesaManuale.importo}
                        onChange={(e) => setSpesaManuale({ ...spesaManuale, importo: e.target.value })}
                    />

                    <label style={{ display: "block", marginBottom: "0.5rem", marginTop: "1rem", fontSize: "0.9rem", opacity: 0.7 }}>Categoria di Spesa</label>
                    <select
                        className="ios-input"
                        style={{ appearance: "none" }}
                        value={spesaManuale.categoria}
                        onChange={(e) => setSpesaManuale({ ...spesaManuale, categoria: e.target.value })}
                    >
                        <option value="Alimenti">🛒 Alimenti</option>
                        <option value="Ristoranti">🍽️ Ristoranti / Trasferte</option>
                        <option value="Salute">💊 Salute</option>
                        <option value="Lavoro">💼 Lavoro / Affitto Studio</option>
                        <option value="Cancelleria">📎 Cancelleria</option>
                        <option value="Software">💻 Software</option>
                        <option value="Auto/Trasporti">🚗 Auto/Trasporti</option>
                        <option value="Carburante">⛽ Carburante</option>
                        <option value="Viaggi">✈️ Viaggi</option>
                        <option value="Tasse">🏦 Tasse</option>
                        <option value="Senza Tasse">🆓 Senza Tasse</option>
                        <option value="Utenze">💡 Utenze Promiscue</option>
                        <option value="Formazione">📚 Formazione</option>
                        <option value="Abbigliamento">👔 Abbigliamento</option>
                        <option value="Imprevisti">⚠️ Imprevisti</option>
                        <option value="Altro">📦 Altro</option>
                    </select>

                    {/* BADGE DEDUCIBILITA' IN TEMPO REALE */}
                    {regimeCorrente === "ordinario" && importoCorrettoManuale > 0 && (
                        <div style={{ marginTop: "1rem", padding: "10px", background: "rgba(52, 199, 89, 0.1)", border: "1px solid var(--success)", borderRadius: "8px", color: "var(--success)", fontSize: "0.9rem", display: "flex", alignItems: "center", gap: "8px", animation: "slideUp 0.3s ease-out" }}>
                            <span style={{ fontSize: "1.2rem" }}>💡</span>
                            <div>
                                <strong>Ordinario:</strong> Importo deducibile ai fini IRPEF stimato:
                                <strong style={{ marginLeft: "4px" }}>€{(importoCorrettoManuale * percentualeAttualeManuale).toFixed(2)}</strong>
                            </div>
                        </div>
                    )}

                    <label style={{ display: "block", marginBottom: "0.5rem", marginTop: "1rem", fontSize: "0.9rem", opacity: 0.7 }}>Descrizione (Opzionale)</label>
                    <input
                        type="text"
                        placeholder="Es. Cena di lavoro ristorante"
                        className="ios-input"
                        value={spesaManuale.descrizione}
                        onChange={(e) => setSpesaManuale({ ...spesaManuale, descrizione: e.target.value })}
                    />

                    <button
                        className="ios-btn-large"
                        style={{ marginTop: "1.5rem" }}
                        onClick={salvaSpesaManuale}
                        disabled={isSaving}
                    >
                        {isSaving ? "Salvataggio..." : "Aggiungi Spesa"}
                    </button>
                </div>
            )}
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useUser, useSession } from "@clerk/nextjs";
import { Book } from "lucide-react";
import { createClient } from "@supabase/supabase-js";

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;

export default function Tasse() {
    const { isLoaded, isSignedIn, user } = useUser();
    const { session } = useSession();

    const getSupabase = () => {
        return createClient(supabaseUrl, supabaseKey, {
            global: {
                fetch: async (url, options = {}) => {
                    let clerkToken;
                    try {
                        clerkToken = await session?.getToken({ template: 'supabase' });
                    } catch {
                        console.warn("Nessun template 'supabase' trovato in Clerk, uso token default");
                        clerkToken = await session?.getToken();
                    }
                    const headers = new Headers(options?.headers);
                    if (clerkToken) headers.set('Authorization', `Bearer ${clerkToken}`);
                    return fetch(url, { ...options, headers, cache: 'no-store' });
                },
            },
        });
    };
    const [mod, setMod] = useState<"auto" | "manual">("auto");

    // Stati per Calcolatore Manuale
    const [lordo, setLordo] = useState<string>("");
    const [regime, setRegime] = useState<"forfettario_5" | "forfettario_15" | "ordinario" | "free">("forfettario_15");
    const [scaglioneManuale, setScaglioneManuale] = useState<number>(43);
    const [risultatoManuale, setRisultatoManuale] = useState<Record<string, number> | null>(null);

    interface CausaDettaglio {
        id: string;
        nome: string;
        data: string;
        lordo: number;
        tasse: number;
        cassa: number;
        netto: number;
        regime: string;
    }

    const [datiAnnuali, setDatiAnnuali] = useState({
        incassatoLordo: 0,
        tasseDaPagare: 0,
        cassaDaPagare: 0,
        nettoTasche: 0,
        speseDeducibili: 0
    });
    const [dettagliCause, setDettagliCause] = useState<CausaDettaglio[]>([]);
    const [isLoadingDati, setIsLoadingDati] = useState(true);
    const [showTutorial, setShowTutorial] = useState(false);

    useEffect(() => {
        if (isSignedIn && user && mod === "auto") {
            calcolaTasseAnnualiReali();
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isSignedIn, user, mod]);

    const calcolaTasseAnnualiReali = async () => {
        setIsLoadingDati(true);
        try {
            const supabase = getSupabase();
            // 1. Prendi tutte le Cause dell'anno corrente
            const currentYear = new Date().getFullYear();
            const startOfYear = `${currentYear}-01-01`;
            const endOfYear = `${currentYear}-12-31`;

            const { data: cause, error: errCause } = await supabase
                .from('cause')
                .select('*')
                .eq('user_id', user?.id)
                .gte('data_sentenza', startOfYear)
                .lte('data_sentenza', endOfYear);

            if (errCause) {
                console.error("Errore fetch cause annue:", errCause);
            }

            const { data: profile } = await supabase
                .from('profiles')
                .select('expected_irpef_bracket')
                .eq('user_id', user?.id)
                .single();

            let currentScaglione = 33;
            if (profile?.expected_irpef_bracket) {
                currentScaglione = parseInt(profile.expected_irpef_bracket);
                setScaglioneManuale(currentScaglione); // Init simulatore col valore utente
            }

            // 2. Prendi tutte le Spese dell'anno corrente
            const { data: spese } = await supabase
                .from('transazioni')
                .select('importo, importo_deducibile, categoria')
                .eq('user_id', user?.id)
                .eq('tipo', 'uscita')
                .gte('data_transazione', startOfYear)
                .lte('data_transazione', endOfYear);

            const speseTotaliDeducibili = (spese || []).reduce((acc, curr) => acc + Number(curr.importo_deducibile ?? curr.importo), 0);

            let totLordo = 0;
            let totTasse = 0;
            let totCassa = 0;
            let totNetto = 0;

            let imponibileOrdinarioAnnuo = 0;
            let totCpaOrdinario = 0;
            let totIvaOrdinario = 0;
            let totRitenutaOrdinario = 0;

            let causeDettaglio: CausaDettaglio[] = [];

            if (cause) {
                cause.forEach(c => {
                    const compensoBase = Number(c.compenso_base || c.compenso_lordo || 0);
                    const r = c.tipologia_fiscale || "forfettario_15";

                    let detLordo = 0;
                    let detTasse = 0;
                    let detCassa = 0;
                    let detNetto = 0;

                    if (r === "forfettario_5" || r === "forfettario_15") {
                        const speseGenerali = compensoBase * 0.15;
                        const redditoImponibileLordo = (compensoBase + speseGenerali) * 0.78;

                        const cassaSoggettiva = redditoImponibileLordo * 0.17;
                        const cpa = c.cpa_4 ? Number(c.cpa_4) : (compensoBase + speseGenerali) * 0.04;
                        const cassaForenseTotale = cassaSoggettiva + cpa;

                        const aliquota = r === "forfettario_5" ? 0.05 : 0.15;
                        const tasse = redditoImponibileLordo * aliquota;

                        // Per forfettario volume d'affari è Compenso base + 15% spese + CPA in fattura (esente IVA)
                        const volumeAffari = c.compenso_lordo ? Number(c.compenso_lordo) : (compensoBase + speseGenerali + cpa);

                        totLordo += volumeAffari;
                        totTasse += tasse;
                        totCassa += cassaForenseTotale;

                        detLordo = volumeAffari;
                        detTasse = tasse;
                        detCassa = cassaForenseTotale;
                        detNetto = volumeAffari - tasse - cassaForenseTotale;

                    } else if (r === "ordinario") {
                        const speseGenerali = compensoBase * 0.15;
                        imponibileOrdinarioAnnuo += (compensoBase + speseGenerali);

                        const cpa = c.cpa_4 ? Number(c.cpa_4) : (compensoBase + speseGenerali) * 0.04;
                        const iva = c.iva_22 ? Number(c.iva_22) : (compensoBase + speseGenerali + cpa) * 0.22;

                        totCpaOrdinario += cpa;
                        totIvaOrdinario += iva;
                        const ritenutaItem = c.ritenuta_20 ? Number(c.ritenuta_20) : 0;
                        totRitenutaOrdinario += ritenutaItem;

                        const volumeAffari = c.compenso_lordo ? Number(c.compenso_lordo) : (compensoBase + speseGenerali + cpa + iva);
                        totLordo += volumeAffari;

                        // Calcolo proporzionale singola fattura per lo spaccato visivo
                        const imponibileCassaItem = compensoBase + speseGenerali;
                        const cassaSoggettivaItem = imponibileCassaItem * 0.17;
                        const cassaForenseItem = cassaSoggettivaItem + cpa;

                        const imponibileIrpefItem = imponibileCassaItem - cassaSoggettivaItem;
                        const irpefItem = imponibileIrpefItem * (currentScaglione / 100.0);
                        const addizionaliItem = imponibileIrpefItem * 0.03;

                        const tasseItem = iva + irpefItem + addizionaliItem - ritenutaItem;

                        detLordo = volumeAffari;
                        detTasse = tasseItem;
                        detCassa = cassaForenseItem;
                        detNetto = volumeAffari - tasseItem - cassaForenseItem;
                    }

                    causeDettaglio.push({
                        id: c.id,
                        nome: c.nome_causa || "Senza Nome",
                        data: c.data_registrazione || c.created_at || new Date().toISOString(),
                        lordo: detLordo,
                        tasse: detTasse,
                        cassa: detCassa,
                        netto: detNetto,
                        regime: r
                    });
                });
            }

            if (imponibileOrdinarioAnnuo > 0) {
                // Sottraiamo le spese deducibili dall'imponibile di cassa ordinario
                let imponibileCassa = imponibileOrdinarioAnnuo - speseTotaliDeducibili;
                if (imponibileCassa < 0) imponibileCassa = 0;

                const cassaSoggettiva = imponibileCassa * 0.17;
                const cassaForenseTotale = cassaSoggettiva + totCpaOrdinario;

                const imponibileIrpef = imponibileCassa - cassaSoggettiva;
                // Calcolo IRPEF basato sullo scaglione previsionale utente
                const irpef = imponibileIrpef * (currentScaglione / 100.0);
                const addizionali = imponibileIrpef * 0.03;

                const fiscoTotale = totIvaOrdinario + irpef + addizionali - totRitenutaOrdinario;

                totTasse += fiscoTotale;
                totCassa += cassaForenseTotale;
            }

            totNetto = totLordo - totTasse - totCassa;

            setDatiAnnuali({
                incassatoLordo: totLordo,
                tasseDaPagare: totTasse,
                cassaDaPagare: totCassa,
                nettoTasche: totNetto,
                speseDeducibili: speseTotaliDeducibili
            });
            setDettagliCause(causeDettaglio);

        } catch (error) {
            console.error("Errore nel calcolo tasse reali", error);
        } finally {
            setIsLoadingDati(false);
        }
    };

    const calcolaManuale = () => {
        const importoLordo = parseFloat(lordo.replace(",", "."));
        if (isNaN(importoLordo) || importoLordo <= 0) return;

        let imponibile = 0, tasse = 0, cassa = 0, netto = 0, volumeAffariLordo = 0;

        if (regime === "forfettario_5" || regime === "forfettario_15") {
            const compensoBase = importoLordo;
            const speseGenerali = compensoBase * 0.15;
            const redditoImponibileLordo = (compensoBase + speseGenerali) * 0.78;

            const cassaSoggettiva = redditoImponibileLordo * 0.17;
            const cpa = (compensoBase + speseGenerali) * 0.04;
            cassa = cassaSoggettiva + cpa;

            const aliquotaTasse = regime === "forfettario_5" ? 0.05 : 0.15;
            tasse = redditoImponibileLordo * aliquotaTasse;

            volumeAffariLordo = compensoBase + speseGenerali + cpa;
            imponibile = redditoImponibileLordo;
            netto = volumeAffariLordo - tasse - cassa;
        } else if (regime === "ordinario") {
            const compensoBase = importoLordo;
            const speseGenerali = compensoBase * 0.15;
            const speseDeducibili = 0; // Simulazione manuale non ha spese caricate

            const imponibileCassa = (compensoBase + speseGenerali) - speseDeducibili;
            const cassaSoggettiva = imponibileCassa * 0.17;
            const cpa = (compensoBase + speseGenerali) * 0.04;
            cassa = cassaSoggettiva + cpa;

            const ivaDaVersare = (compensoBase + speseGenerali + cpa) * 0.22;

            const imponibileIrpef = imponibileCassa - cassaSoggettiva;
            const irpef = imponibileIrpef * (scaglioneManuale / 100.0); // Simulazione su scaglione scelto
            const addizionali = imponibileIrpef * 0.03;
            tasse = ivaDaVersare + irpef + addizionali;

            volumeAffariLordo = compensoBase + speseGenerali + cpa + ivaDaVersare;
            imponibile = imponibileIrpef;
            netto = volumeAffariLordo - tasse - cassa;
        } else {
            // Free
            imponibile = 0; tasse = 0; cassa = 0; netto = importoLordo; volumeAffariLordo = importoLordo;
        }

        setRisultatoManuale({ imponibile, tasse, cassa, netto, volumeAffariLordo });
    };

    if (!isLoaded || !isSignedIn) return null;

    return (
        <div className="pb-20">
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: "1rem" }}>
                <h1 style={{ marginBottom: 0 }}>Cassetto Fiscale {new Date().getFullYear()}</h1>
                <button
                    onClick={() => setShowTutorial(true)}
                    style={{ background: "none", border: "none", cursor: "pointer", color: "#007AFF", padding: "0.5rem" }}
                    aria-label="Apri guida"
                >
                    <Book size={28} />
                </button>
            </div>

            {/* Segmented Control per passare da DB a Simulatore */}
            <div className="ios-select-group" style={{ marginBottom: "2rem" }}>
                <button
                    className={`ios-segment ${mod === "auto" ? "active" : ""}`}
                    onClick={() => setMod("auto")}
                >
                    📊 Bilancio Reale
                </button>
                <button
                    className={`ios-segment ${mod === "manual" ? "active" : ""}`}
                    onClick={() => setMod("manual")}
                >
                    🧮 Simulatore
                </button>
            </div>

            {mod === "auto" && (
                <>
                    {isLoadingDati ? (
                        <div style={{ textAlign: "center", padding: "2rem", opacity: 0.5 }}>Calcolo bilanci in corso...</div>
                    ) : datiAnnuali.incassatoLordo === 0 ? (
                        <div style={{ textAlign: "center", padding: "3rem 1rem", opacity: 0.6 }}>
                            <div style={{ fontSize: "3rem", marginBottom: "1rem" }}>🏛️</div>
                            Ancora nessuna fattura o incasso registrato nel {new Date().getFullYear()}. Le tasse appariranno qui automaticamente appena registrerai una causa!
                        </div>
                    ) : (
                        <div className="ios-card" style={{ animation: "slideUp 0.3s ease-out" }}>
                            <h2 style={{ textAlign: "center", marginBottom: "1.5rem" }}>Quadro Riassuntivo Annuo</h2>

                            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "1rem", borderBottom: "1px solid var(--border)", paddingBottom: "0.5rem" }}>
                                <span style={{ opacity: 0.8 }}>Volume d&apos;Affari Lordo</span>
                                <span style={{ fontWeight: "600", color: "var(--foreground)" }}>€{datiAnnuali.incassatoLordo.toFixed(2)}</span>
                            </div>

                            <div style={{ marginBottom: "1rem", borderBottom: "1px solid var(--border)", paddingBottom: "0.5rem" }}>
                                <div style={{ color: "var(--destructive)", marginBottom: "0.5rem" }}>Fisco (IRPEF/Sostitutiva) da pagare:</div>
                                {dettagliCause.map(c => (
                                    <div key={c.id} style={{ display: "flex", justifyContent: "space-between", fontSize: "0.9rem", marginLeft: "0.5rem", marginBottom: "0.25rem", opacity: 0.9 }}>
                                        <span>{c.nome}</span>
                                        <span>- €{c.tasse.toFixed(2)}</span>
                                    </div>
                                ))}
                                <div style={{ display: "flex", justifyContent: "space-between", marginTop: "0.5rem", fontWeight: "bold", color: "var(--destructive)" }}>
                                    <span>Totale Tasse</span>
                                    <span>- €{datiAnnuali.tasseDaPagare.toFixed(2)}</span>
                                </div>
                            </div>

                            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "1rem", borderBottom: "1px solid var(--border)", paddingBottom: "0.5rem", color: "var(--destructive)" }}>
                                <span>Cassa Forense stimata</span>
                                <span style={{ fontWeight: "bold" }}>- €{datiAnnuali.cassaDaPagare.toFixed(2)}</span>
                            </div>

                            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "1rem", borderBottom: "1px solid var(--border)", paddingBottom: "0.5rem", color: "var(--primary)" }}>
                                <span>Spese / Costi affrontati</span>
                                <span style={{ fontWeight: "600" }}>- €{datiAnnuali.speseDeducibili.toFixed(2)}</span>
                            </div>

                            <div style={{ display: "flex", justifyContent: "space-between", paddingTop: "0.5rem", fontSize: "1.2rem", fontWeight: "bold", color: "var(--success)" }}>
                                <span>Netto in Tasca Stimato</span>
                                <span>€{datiAnnuali.nettoTasche.toFixed(2)}</span>
                            </div>
                        </div>
                    )}

                    {/* Spaccato Causale */}
                    {dettagliCause.length > 0 && mod === "auto" && datiAnnuali.incassatoLordo > 0 && (
                        <div style={{ marginTop: "2rem", animation: "slideUp 0.4s ease-out" }}>
                            <h2 style={{ marginBottom: "1rem" }}>Spaccato Singole Entrate</h2>
                            {dettagliCause.map(c => (
                                <div key={c.id} className="ios-card" style={{ marginBottom: "1rem", padding: "1rem" }}>
                                    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "0.5rem" }}>
                                        <h3 style={{ margin: 0, fontSize: "1.1rem" }}>{c.nome}</h3>
                                        <span style={{ fontSize: "0.8rem", opacity: 0.6 }}>
                                            {new Date(c.data).toLocaleDateString()}
                                        </span>
                                    </div>
                                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: "0.9rem", marginBottom: "4px" }}>
                                        <span>Ritornato in Fattura (Lordo):</span>
                                        <span style={{ fontWeight: "bold" }}>€{c.lordo.toFixed(2)}</span>
                                    </div>
                                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: "0.9rem", marginBottom: "4px", color: "var(--destructive)" }}>
                                        <span>Fisco (IRPEF/IVA/Sost):</span>
                                        <span>- €{c.tasse.toFixed(2)}</span>
                                    </div>
                                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: "0.9rem", marginBottom: "4px", color: "var(--destructive)" }}>
                                        <span>Cassa (CPA+Sogg):</span>
                                        <span>- €{c.cassa.toFixed(2)}</span>
                                    </div>
                                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: "1rem", marginTop: "8px", paddingTop: "8px", borderTop: "1px solid var(--border)", color: "var(--success)", fontWeight: "bold" }}>
                                        <span>Netto Effettivo:</span>
                                        <span>€{c.netto.toFixed(2)}</span>
                                    </div>
                                    {c.regime === "ordinario" && (
                                        <div style={{ fontSize: "0.75rem", opacity: 0.6, marginTop: "6px", textAlign: "right" }}>
                                            *Stima pre-deduzioni annuali
                                        </div>
                                    )}
                                </div>
                            ))}
                        </div>
                    )}
                </>
            )}

            {mod === "manual" && (
                <>
                    <p>Simula l&apos;incasso di una fattura o del lordo per visualizzare il netto stimato ad personam.</p>
                    <div className="ios-card" style={{ animation: "slideUp 0.3s ease-out" }}>
                        <label style={{ display: "block", marginBottom: "0.5rem", fontWeight: "600" }}>
                            Incasso Lordo (€)
                        </label>
                        <input
                            type="number"
                            value={lordo}
                            onChange={(e) => setLordo(e.target.value)}
                            placeholder="Es: 1500"
                            className="ios-input"
                        />

                        <label style={{ display: "block", marginTop: "1rem", marginBottom: "0.5rem", fontWeight: "600" }}>
                            Regime Fiscale del singolo compenso
                        </label>

                        <div className="ios-select-group" style={{ flexDirection: "column" }}>
                            <button
                                className={`ios-segment ${regime === 'forfettario_5' ? 'active' : ''}`}
                                onClick={() => setRegime('forfettario_5')}
                            >
                                Forfettario (5%)
                            </button>
                            <button
                                className={`ios-segment ${regime === 'forfettario_15' ? 'active' : ''}`}
                                onClick={() => setRegime('forfettario_15')}
                            >
                                Forfettario (15%)
                            </button>
                            <button
                                className={`ios-segment ${regime === 'ordinario' ? 'active' : ''}`}
                                onClick={() => setRegime('ordinario')}
                            >
                                Ordinario
                            </button>
                            <button
                                className={`ios-segment ${regime === 'free' ? 'active' : ''}`}
                                onClick={() => setRegime('free')}
                            >
                                Esente / Senza Tasse
                            </button>
                        </div>

                        {regime === 'ordinario' && (
                            <>
                                <label style={{ display: "block", marginTop: "1rem", marginBottom: "0.5rem", fontWeight: "600" }}>
                                    Scaglione IRPEF Sceglibile (Simulazione)
                                </label>
                                <div className="ios-select-group" style={{ marginBottom: "1rem" }}>
                                    <button
                                        className={`ios-segment ${scaglioneManuale === 23 ? 'active' : ''}`}
                                        onClick={() => setScaglioneManuale(23)}
                                    >23%</button>
                                    <button
                                        className={`ios-segment ${scaglioneManuale === 33 ? 'active' : ''}`}
                                        onClick={() => setScaglioneManuale(33)}
                                    >33%</button>
                                    <button
                                        className={`ios-segment ${scaglioneManuale === 43 ? 'active' : ''}`}
                                        onClick={() => setScaglioneManuale(43)}
                                    >43%</button>
                                </div>
                            </>
                        )}

                        <button className="ios-btn-large" onClick={calcolaManuale}>
                            Calcola Netto
                        </button>
                    </div>

                    {risultatoManuale && (
                        <div className="ios-card" style={{ marginTop: "1rem", background: "rgba(0,122,255,0.05)", borderColor: "var(--primary)" }}>
                            <h2 style={{ textAlign: "center", marginBottom: "1.5rem" }}>Risultato Simulato</h2>

                            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "1rem", borderBottom: "1px solid var(--border)", paddingBottom: "0.5rem" }}>
                                <span>Volume d&apos;Affari Lordo</span>
                                <span style={{ fontWeight: "600", color: "var(--foreground)" }}>€{risultatoManuale.volumeAffariLordo.toFixed(2)}</span>
                            </div>

                            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "1rem", borderBottom: "1px solid var(--border)", paddingBottom: "0.5rem" }}>
                                <span style={{ opacity: 0.8 }}>Compenso Base Inserito</span>
                                <span style={{ fontWeight: "600" }}>€{parseFloat(lordo).toFixed(2)}</span>
                            </div>

                            {regime !== 'free' && (
                                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "1rem", borderBottom: "1px solid var(--border)", paddingBottom: "0.5rem" }}>
                                    <span style={{ opacity: 0.8 }}>Imponibile Tassabile (Cassa Dedotta)</span>
                                    <span style={{ fontWeight: "600" }}>€{risultatoManuale.imponibile.toFixed(2)}</span>
                                </div>
                            )}

                            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "1rem", borderBottom: "1px solid var(--border)", paddingBottom: "0.5rem", color: "var(--destructive)" }}>
                                <span>Tasse (IRPEF/Sostitutiva)</span>
                                <span style={{ fontWeight: "600" }}>- €{risultatoManuale.tasse.toFixed(2)}</span>
                            </div>

                            <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "1rem", borderBottom: "1px solid var(--border)", paddingBottom: "0.5rem", color: "var(--destructive)" }}>
                                <span>Cassa Forense</span>
                                <span style={{ fontWeight: "600" }}>- €{risultatoManuale.cassa.toFixed(2)}</span>
                            </div>

                            <div style={{ display: "flex", justifyContent: "space-between", marginTop: "1.5rem", fontSize: "1.5rem" }}>
                                <strong>Netto Stimato</strong>
                                <strong style={{ color: "var(--success)" }}>€{risultatoManuale.netto.toFixed(2)}</strong>
                            </div>
                        </div>
                    )}
                </>
            )}

            {/* Modale Tutorial & Legenda */}
            {showTutorial && (
                <div style={{
                    position: "fixed", top: 0, left: 0, right: 0, bottom: 0,
                    backgroundColor: "rgba(0,0,0,0.5)", zIndex: 9999,
                    display: "flex", alignItems: "center", justifyContent: "center",
                    padding: "1rem"
                }}>
                    <div className="ios-card" style={{
                        maxWidth: "500px", width: "100%", maxHeight: "80vh", overflowY: "auto",
                        position: "relative", animation: "slideUp 0.3s ease-out"
                    }}>
                        <button
                            onClick={() => setShowTutorial(false)}
                            style={{ position: "absolute", top: "1rem", right: "1rem", background: "none", border: "none", fontSize: "1.5rem", cursor: "pointer", color: "var(--foreground)" }}
                        >
                            ✕
                        </button>
                        <h2 style={{ display: "flex", alignItems: "center", gap: "0.5rem", marginBottom: "1rem", color: "#007AFF" }}>
                            <Book size={24} /> Guida all'App
                        </h2>

                        <div style={{ marginBottom: "1.5rem" }}>
                            <h3 style={{ fontSize: "1.1rem", marginBottom: "0.5rem" }}>Come utilizzare l'App</h3>
                            <ul style={{ paddingLeft: "1.2rem", margin: 0, opacity: 0.9 }}>
                                <li><strong>Dashboard:</strong> Aggiungi qui le tue cause (entrate) e le tue spese (uscite). Scannerizza gli scontrini per un inserimento rapido.</li>
                                <li><strong>Cassetto Fiscale:</strong> Visualizza in automatico le tasse, la cassa forense e il netto in tasca, calcolati in base alle entrate e uscite registrate.</li>
                                <li><strong>Simulatore:</strong> Usa la sezione "Simulatore" per calcolare tasse e netto di un ipotetico incasso futuro, senza salvarlo nel database.</li>
                                <li><strong>Impostazioni:</strong> Configura il tuo regime fiscale e la cassa forense standard per i calcoli automatici.</li>
                            </ul>
                        </div>

                        <div style={{ background: "rgba(0,122,255,0.05)", padding: "1rem", borderRadius: "12px" }}>
                            <h3 style={{ fontSize: "1.1rem", marginBottom: "0.5rem" }}>Regime Ordinario: Spese Deducibili</h3>
                            <p style={{ fontSize: "0.9rem", opacity: 0.9, marginBottom: "0.5rem" }}>
                                Se sei nel regime Ordinario, l'app abbatte automaticamente il tuo imponibile in base alla categoria della spesa:
                            </p>
                            <ul style={{ paddingLeft: "1.2rem", margin: 0, fontSize: "0.9rem" }}>
                                <li style={{ marginBottom: "4px" }}><strong>100% (Interamente deducibili):</strong> Cancelleria, Software, Spese per il Lavoro, Formazione. (Es: un PC o un corso).</li>
                                <li style={{ marginBottom: "4px" }}><strong>75% (Parzialmente deducibili):</strong> Ristoranti, Alberghi, Somministrazione alimenti e bevande per riunioni/trasferte.</li>
                                <li style={{ marginBottom: "4px" }}><strong>20% (Uso promiscuo):</strong> Auto, Trasporti, Carburante, Viaggi.</li>
                                <li><strong>0% (Non deducibili):</strong> Alimenti generici, spese personali, imprevisti.</li>
                            </ul>
                            <p style={{ fontSize: "0.85rem", opacity: 0.7, marginTop: "0.5rem", fontStyle: "italic" }}>
                                *Per il regime Forfettario le spese reali non si scaricano (esiste una deduzione forfettaria integrata del 15% o altra percentuale).
                            </p>
                        </div>
                    </div>
                </div>
            )}
            <style dangerouslySetInnerHTML={{
                __html: `
        @keyframes slideUp {
          from { transform: translateY(20px); opacity: 0; }
          to { transform: translateY(0); opacity: 1; }
        }
      `}} />
        </div>
    );
}
